/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../input/BTInputClear.css';

/*
 * BTInputTime — masked time text-input field.
 * Figma node 555-2975.
 *
 * Layout follows BTInputDate exactly — position:relative on the field div,
 * label is position:absolute inside it. No popover panel.
 *
 * Visual structure (flex-row, height 48px — same as BTInputDate):
 * ┌── field (position:relative) ────────────────────────────────┐
 * │  [🕐 16px] │  label (absolute, resting↔floating) │  input  │ [×?] │
 * └──────────────────────────────────────────────────────────────┘
 */

/* ── Outer wrapper ───────────────────────────────────────────── */
.bt-input-time__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field row ───────────────────────────────────────────────── */
.bt-input-time {
  position: relative;
  display: flex;
  align-items: center;
  height: 48px;
  box-sizing: border-box;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  padding: 0 8px;
  gap: var(--space-sm);
  cursor: text;
  user-select: none;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--label-floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* States */
.bt-input-time--focused  { border-color: var(--color-brand-primary); }
.bt-input-time--error    { border-color: var(--text-error); }
.bt-input-time--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Clock icon ──────────────────────────────────────────────── */
.bt-input-time__icon {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
}

.bt-input-time__icon img,
.bt-input-time__icon svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-input-time--focused  .bt-input-time__icon { color: var(--color-brand-primary); }
.bt-input-time--error    .bt-input-time__icon { color: var(--text-error); }
.bt-input-time--disabled .bt-input-time__icon { color: var(--text-disabled); }

/* ── Floating label ──────────────────────────────────────────── */
/*
 * left: 32px = 8px(pad) + 16px(icon) + 8px(gap)
 */
.bt-input-time__label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-2xl);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 56px);
  transition: top        150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform  150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size  150ms cubic-bezier(0.4, 0, 0.2, 1),
              color      150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--label-floating .bt-input-time__label {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

.bt-input-time--focused  .bt-input-time__label { color: var(--color-brand-primary); }
.bt-input-time--error    .bt-input-time__label { color: var(--text-error); }
.bt-input-time--disabled .bt-input-time__label { color: var(--text-disabled); }

.bt-input-time__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Native <input> ──────────────────────────────────────────── */
.bt-input-time__input {
  flex: 1;
  height: 100%;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  caret-color: var(--color-brand-primary);
  padding: 0;
  transition: padding-top 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--label-floating .bt-input-time__input {
  padding-top: 14px;
  align-self: flex-start;
}

.bt-input-time__input::placeholder {
  color: var(--text-secondary);
  font-weight: 500;
}

.bt-input-time--disabled .bt-input-time__input {
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* ── AM/PM toggle button ─────────────────────────────────────── */
.bt-input-time__ampm {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  font-size: var(--typography-font-size-xs);
  font-weight: 600;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  background: var(--bg-subtle);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  padding: 2px 6px;
  cursor: pointer;
  user-select: none;
  transition: color 150ms, background 150ms, border-color 150ms;
}

.bt-input-time--focused .bt-input-time__ampm {
  color: var(--color-brand-primary);
  border-color: var(--color-brand-primary);
}

.bt-input-time--disabled .bt-input-time__ampm {
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* ── Clear (×) button ────────────────────────────────────────── */
.bt-input-time__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-time__clear img,
.bt-input-time__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Helper / error text ─────────────────────────────────────── */
.bt-input-time__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-time__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-time__helper-text--error { color: var(--text-error); }

/* ── Small variant ───────────────────────────────────────────── */
.bt-input-time--small {
  height: auto;
  padding-top: 12px;
  padding-bottom: 12px;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--small.bt-input-time--label-floating {
  padding-top: 4px;
  padding-bottom: 4px;
}

.bt-input-time--small.bt-input-time--label-floating .bt-input-time__label {
  top: var(--space-xs);
}

.bt-input-time--small .bt-input-time__input {
  height: auto;
  font-size: var(--typography-font-size-xs);
}

.bt-input-time--small.bt-input-time--label-floating .bt-input-time__input {
  padding-top: 16px;
  align-self: flex-start;
}

/**
 * BTInputTime — masked time-input field.
 * Figma node 555-2975.
 *
 * @example
 * <BTInputTime label="Start time" v-model="time" />
 * <BTInputTime label="Duration" format="HH:mm:ss" v-model="duration" />
 * <BTInputTime label="Meeting" format="hh:mm a" v-model="meeting" />
 */

export type BTInputTimeFormat = 'HH:mm' | 'HH:mm:ss' | 'hh:mm a';

export type BTInputTimeSize = 'default' | 'small';

export interface BTInputTimeProps {
  /** Current time value — string matching the active format.
   *  e.g. "17:58" for HH:mm, "17:58:30" for HH:mm:ss, "05:30 PM" for hh:mm a.
   *  Pass null to clear. */
  modelValue?: string | null;

  /** Floating label text. */
  label?: string;

  /**
   * Display and input format.
   * - 'HH:mm'    → 24-hour, 4 digits (HHMM)
   * - 'HH:mm:ss' → 24-hour with seconds, 6 digits (HHMMSS)
   * - 'hh:mm a'  → 12-hour, 4 digits + AM/PM toggle
   * @default 'HH:mm'
   */
  format?: BTInputTimeFormat;

  /** Field height variant.
   * - default: 48 px fixed height, padding-y 8 px / 8 px (floating)
   * - small:   ~40 px auto height, padding-y 12 px / 4 px (floating), value font 12 px
   * @default 'default'
   */
  size?: BTInputTimeSize;

  disabled?: boolean;
  readOnly?: boolean;
  required?: boolean;

  /** External error message — overrides internal validator error. */
  errorText?: string;

  /** Helper text shown below the field. */
  helperText?: string;

  /** Override the generated `id` used for label association. */
  id?: string;
}
